return (() => {
  const maxResults = Number('{{max_results}}') || 20;
  const items = Array.from(document.querySelectorAll('a[id^="item_id_"]')).slice(0, maxResults);
  return items.map((el, idx) => {
    const id = (el.id || '').replace('item_id_', '');
    const titleEl = el.querySelector('[class*="title--"]');
    const title = (titleEl?.textContent || '').replace(/\s+/g, ' ').trim();
    const priceInt = (el.querySelector('[class*="priceInt--"]')?.textContent || '').trim();
    const priceFloat = (el.querySelector('[class*="priceFloat--"]')?.textContent || '').trim();
    const price = '¥' + priceInt + priceFloat;
    const sales = (el.querySelector('[class*="realSales--"]')?.textContent || '').trim();
    const img = (el.querySelector('img[class*="mainPic--"]') || el.querySelector('img'))?.src || '';
    const shopName = (el.querySelector('[class*="shopNameText--"]')?.textContent || '').trim();
    const shopTag = (el.querySelector('[class*="shopTagText--"]')?.textContent || '').trim();
    const locationSpans = el.querySelectorAll('[class*="procity--"] span');
    const location = Array.from(locationSpans).map(s => (s.textContent || '').trim()).filter(Boolean).join(' ');
    const tagSpans = el.querySelectorAll('[class*="subIconWrapper--"] span');
    const tags = Array.from(tagSpans).map(s => (s.textContent || '').trim()).filter(Boolean);
    const href = el.href || '';
    return { index: idx + 1, id, title, price, sales, location, shopName, shopTag, tags, img, url: href };
  });
})();

return (() => {
  const t = (el) => (el?.textContent || '').replace(/\s+/g, ' ').trim();
  const titleEl = document.querySelector('span[class*="mainTitle--"]');
  const title = titleEl?.getAttribute('title') || t(titleEl) || t(document.querySelector('h1, .tb-main-title'));
  const currentPriceEl = document.querySelector('[class*="highlightPrice--"] [class*="text--"]');
  const currentPrice = t(currentPriceEl);
  const currentPriceLabel = t(document.querySelector('[class*="highlightPrice--"] [class*="title--"]'));
  const originalPriceEls = document.querySelectorAll('[class*="subPrice--"] [class*="text--"]');
  const originalPrice = Array.from(originalPriceEls).map(el => t(el)).filter(v => /\d/.test(v)).join('');
  const promoLabel = t(document.querySelector('[class*="bottomLabel--"] [class*="text--"]'));
  const skuSections = document.querySelectorAll('[class*="skuItem--"]');
  const skus = Array.from(skuSections).map(section => {
    const label = t(section.querySelector('[class*="ItemLabel--"] span'));
    const values = Array.from(section.querySelectorAll('[class*="valueItem--"][data-vid]')).map(item => {
      const text = item.querySelector('[class*="valueItemText--"]')?.getAttribute('title') || t(item.querySelector('[class*="valueItemText--"]'));
      const selected = /isSelected--/.test(item.className);
      const disabled = item.getAttribute('data-disabled') === 'true';
      const imgEl = item.querySelector('img[class*="valueItemImg--"]');
      const img = imgEl?.src || '';
      const hasRealImg = img && !img.includes('tps-2-2.png');
      return { text, selected, disabled, img: hasRealImg ? img : undefined };
    });
    return { label, options: values };
  });
  const galleryImgs = document.querySelectorAll('[class*="PicGallery"] img, [class*="gallery"] img, [class*="thumbnail"] img, .tb-gallery img');
  const seen = new Set();
  const images = Array.from(galleryImgs).map(img => {
    let src = img.getAttribute('data-src') || img.src || '';
    src = src.replace(/^\/\//, 'https://');
    if (!src || seen.has(src) || src.includes('tps-2-2.png')) return null;
    seen.add(src);
    return src;
  }).filter(Boolean);
  const qaTitle = t(document.querySelector('[class*="askAnswerTitle--"]'));
  const qaCountMatch = qaTitle.match(/(\d+)/);
  const qaCount = qaCountMatch ? Number(qaCountMatch[1]) : 0;
  const qaItems = Array.from(document.querySelectorAll('[class*="askAnswerItem--"]')).map(item => {
    const qEl = item.querySelector('[class*="question--"]');
    const aEl = item.querySelector('[class*="answer--"]');
    const question = qEl?.getAttribute('title') || t(qEl);
    const answer = aEl?.getAttribute('title') || t(aEl);
    return { question, answer };
  }).filter(item => item.question || item.answer);
  const specItems = Array.from(document.querySelectorAll('[class*="generalParamsInfoItem--"]')).map(item => {
    const keyEl = item.querySelector('[class*="generalParamsInfoItemTitle--"]');
    const valEl = item.querySelector('[class*="generalParamsInfoItemSubTitle--"]');
    const key = keyEl?.getAttribute('title') || t(keyEl);
    const value = valEl?.getAttribute('title') || t(valEl);
    return { key, value };
  }).filter(item => item.key);
  const shopNameEl = document.querySelector('[class*="shopName"], [class*="ShopHeader"] a, .tb-shop-name a');
  const shopName = t(shopNameEl);
  return {
    title,
    currentPrice: currentPrice ? '¥' + currentPrice : '',
    currentPriceLabel,
    originalPrice: originalPrice ? '¥' + originalPrice : '',
    promoLabel,
    skus,
    images,
    imageCount: images.length,
    specs: specItems,
    specCount: specItems.length,
    qa: { total: qaCount, items: qaItems, fetchedCount: qaItems.length },
    shopName,
    url: location.href
  };
})();

return (() => {
  const items = Array.from(document.querySelectorAll('li.child-item')).slice(0, 100);
  return items.map((li, idx) => {
    const rankEl = li.querySelector('.left-item span');
    const rank = rankEl ? parseInt(rankEl.textContent || '', 10) || (idx + 1) : (idx + 1);
    const linkEl = li.querySelector('.center-item .medium-txt a');
    const title = (linkEl?.textContent || '').trim();
    const url = linkEl?.href || '';
    const smallTxt = (li.querySelector('.center-item .small-txt')?.textContent || '').trim();
    const parts = smallTxt.split('\u2027').map(s => s.trim());
    const source = parts[0] || '';
    const heat = parts[1] || '';
    const iconEl = li.querySelector('.right-item img');
    const icon = iconEl?.src || '';
    return { rank, title, url, source, heat, icon };
  });
})();
